import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';

const StaffReports = () => {
  const { user } = useAuth();
  const { attendanceLogs, tasks } = useData();
  const [filterType, setFilterType] = useState('Month'); // Day, Week, Month

  // Filter Logic
  const isDateInFilter = (dateStr) => {
      const date = new Date(dateStr);
      const now = new Date();
      if (filterType === 'Day') return date.toDateString() === now.toDateString();
      if (filterType === 'Month') return date.getMonth() === now.getMonth() && date.getFullYear() === now.getFullYear();
      if (filterType === 'Week') {
          const oneWeekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
          return date >= oneWeekAgo && date <= now;
      }
      return true;
  };

  const myLogs = attendanceLogs.filter(log => log.staffId === user.id && isDateInFilter(log.checkIn));

  // Determine Status: Late vs On Time
  const getStatus = (log) => {
      const task = tasks.find(t => t.id === log.taskId);
      if (!task) return "N/A";
      
      const checkInTime = new Date(log.checkIn);
      const startTaskTime = new Date(task.startTime);
      const bufferMs = 5 * 60 * 1000; // 5 mins buffer
      
      if (checkInTime.getTime() > startTaskTime.getTime() + bufferMs) {
          return "Trễ";
      }
      return "Đúng giờ";
  };

  return (
    <div style={{ padding: '20px' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
          <h2 style={{ color: '#003366', margin: 0 }}>Báo cáo Chấm công</h2>
          <select 
            value={filterType} 
            onChange={(e) => setFilterType(e.target.value)}
            style={{ padding: '8px 12px', borderRadius: '6px', border: '1px solid #ccc' }}
          >
              <option value="Day">Hôm nay</option>
              <option value="Week">Tuần này</option>
              <option value="Month">Tháng này</option>
          </select>
      </div>

      <div style={{ background: 'white', borderRadius: '12px', boxShadow: '0 2px 5px rgba(0,0,0,0.1)', overflow: 'hidden' }}>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead style={{ background: '#f9fafb', borderBottom: '1px solid #eee' }}>
                  <tr>
                      <th style={thStyle}>Ngày</th>
                      <th style={thStyle}>Nhiệm vụ</th>
                      <th style={thStyle}>Thời gian bắt đầu</th>
                      <th style={thStyle}>Thời gian hoàn thành</th>
                      <th style={thStyle}>Trạng thái</th>
                  </tr>
              </thead>
              <tbody>
                  {myLogs.length === 0 ? (
                      <tr><td colSpan="5" style={{ padding: '20px', textAlign: 'center', color: '#999' }}>Không có dữ liệu chấm công.</td></tr>
                  ) : (
                      myLogs.map(log => {
                          const status = getStatus(log);
                          return (
                              <tr key={log.id} style={{ borderBottom: '1px solid #f3f4f6' }}>
                                  <td style={tdStyle}>{new Date(log.checkIn).toLocaleDateString('vi-VN')}</td>
                                  <td style={tdStyle}>{log.taskTitle}</td>
                                  <td style={tdStyle}>{new Date(log.checkIn).toLocaleTimeString('vi-VN')}</td>
                                  <td style={tdStyle}>
                                      {log.checkOut ? new Date(log.checkOut).toLocaleTimeString('vi-VN') : 'Chưa out'}
                                  </td>
                                  <td style={tdStyle}>
                                      <span style={{
                                          padding: '4px 8px', borderRadius: '4px', fontSize: '0.8rem', fontWeight: 'bold',
                                          background: status === 'Trễ' ? '#fee2e2' : '#dcfce7',
                                          color: status === 'Trễ' ? '#b91c1c' : '#15803d'
                                      }}>
                                          {status}
                                      </span>
                                  </td>
                              </tr>
                          );
                      })
                  )}
              </tbody>
          </table>
      </div>
    </div>
  );
};

const thStyle = { padding: '12px 15px', textAlign: 'left', color: '#4b5563', fontSize: '0.9rem' };
const tdStyle = { padding: '12px 15px', color: '#1f2937', fontSize: '0.9rem' };

export default StaffReports;
